const raw = $input.first().json;
const payload = raw.body || raw;
const message = payload.message || {};
const chat = payload.chat || {};

// Anti-loop: ignora mensagens proprias
if (message.fromMe === true) {
  return [];
}

// Filtra keyword (case-insensitive, trimmed)
const texto = String(message.text || message.content || '').trim().toLowerCase();
if (texto !== 'rnbsolucoes') {
  return [];
}

// Sanitiza telefone (somente digitos, min 10)
const telefoneBruto = message.sender_pn || chat.phone || '';
const telefone = String(telefoneBruto).replace(/\D/g, '');
if (!telefone || telefone.length < 10) {
  return [];
}

// Extrai nome do contato
const nome = String(
  message.senderName || chat.wa_contactName || chat.name || chat.wa_name || 'Visitante'
).trim();

return [{
  json: {
    nome,
    numero: telefone,
    texto_recebido: texto,
    data_hora: new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' })
  }
}];

const lead = $('Code - Validar Mensagem').first().json;
const allRows = $('Google Sheets - Consultar Leads').all();
const rows = allRows.map(i => i.json).filter(r => r && r.Telefone);

// Busca lead existente pelo telefone
const existing = rows.find(r => {
  const tel = String(r.Telefone || '').replace(/\D/g, '');
  return tel === lead.numero;
});

// Verifica cooldown de 24h
if (existing && existing.Ultimo_Envio) {
  const lastSent = new Date(existing.Ultimo_Envio);
  const now = new Date();
  const hoursElapsed = (now - lastSent) / (1000 * 60 * 60);
  if (hoursElapsed < 24) {
    return [];
  }
}

return [{
  json: {
    ...lead,
    is_new: !existing
  }
}];

